import cirq

def repetition_code_circuit(n: int, error_qubit: int) -> cirq.Circuit:
    if n % 2 == 0:
        raise ValueError("n must be odd")

    qubits = cirq.LineQubit.range(n)
    syndromes = cirq.NamedQubit.range(n - 1, prefix='s')

    circuit = cirq.Circuit()

    # Encode: CNOT q0 -> q1...q(n-1)
    for i in range(1, n):
        circuit.append(cirq.CNOT(qubits[0], qubits[i]))

    # Error
    if 0 <= error_qubit < n:
        circuit.append(cirq.X(qubits[error_qubit]))

    # Syndrome Measurement: Z_i Z_{i+1}
    for i in range(n - 1):
        # Parity of q_i and q_{i+1} into s_i
        circuit.append(cirq.CNOT(qubits[i], syndromes[i]))
        circuit.append(cirq.CNOT(qubits[i+1], syndromes[i]))

    circuit.append(cirq.measure(*syndromes, key='syndromes'))
    return circuit

