def make_oracle(f: Callable[[int], int], n: int) -> cirq.Gate:
    class Oracle(cirq.Gate):
        def num_qubits(self):
            return n + 1

        def _decompose_(self, qubits):
            inputs = qubits[:n]
            ancilla = qubits[n]

            for i in range(2**n):
                if f(i) == 1:
                    # Apply X to ancilla controlled by inputs being in state |i>
                    # We can use X gates to flip 0s to 1s, control, then flip back
                    controls = []
                    for j in range(n):
                        if not (i >> (n - 1 - j)) & 1:
                            yield cirq.X(inputs[j])

                    yield cirq.X(ancilla).controlled_by(*inputs)

                    for j in range(n):
                        if not (i >> (n - 1 - j)) & 1:
                            yield cirq.X(inputs[j])

    return Oracle()

