def run_state_tomography(simulator, qubits, circuit, repetitions=1000):
    """Runs state tomography on the given qubits after applying the circuit."""
    if len(qubits) == 1:
        return cirq.experiments.single_qubit_state_tomography(
            simulator, qubits[0], circuit, repetitions=repetitions
        )
    elif len(qubits) == 2:
        return cirq.experiments.two_qubit_state_tomography(
            simulator, qubits[0], qubits[1], circuit, repetitions=repetitions
        )
    else:
        raise NotImplementedError("Only 1 and 2 qubit tomography supported in this example.")

